1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	
4	const BASE_PRICE_BY_ITEM_TYPE: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	};
10	
11	type Item = { type: string };
12	type Customer = { yearsWithMHPCO: number };
13	
14	const basePriceFor = (item: Item): number =>
15	  BASE_PRICE_BY_ITEM_TYPE[item.type] ?? 0;
16	
17	const priceForItem = (item: Item): number => {
18	  const basePrice = basePriceFor(item);
19	  return basePrice + basePrice * FIRST_INSURANCE_SURCHARGE_RATE;
20	};
21	
22	export const quote = (_customer: Customer, items: Item[]): number => {
23	  const itemsTotal = items.reduce((sum, item) => sum + priceForItem(item), 0);
24	  return itemsTotal + PROCESSING_FEE;
25	};
26	
27	export const claim = (..._args: unknown[]): unknown => {
28	  return undefined;
29	};
